\begin{align*}\cos (\alpha) = \frac{3}{5}~\Leftrightarrow~ \frac{6}{10} = \frac{a}{9} \Longleftrightarrow &a = 9 \cdot \frac{6}{10} = \frac{54}{10} = \boxed{\frac{27}{5}}.\end{align*}
